var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"이제... 끝이다.","JPN":"これで……終わりだ！","ENG":"This... ends now!","TWN":"現在……結束了！"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...지금입니다!","JPN":"今です！","ENG":"Now!","TWN":"就是現在！"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"은폐 역장, 해제!","JPN":"隠蔽力場、発動！","ENG":"Cloaking stasis field, activated!","TWN":"隱蔽力場，啟動！"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"제 모든 힘을 쏟아부어서...! 붙잡을게요!","JPN":"私の力をすべて注いで……！　捕まえます！","ENG":"I'll pour every bit of my strength into this...! I'll hold her down!","TWN":"我會灌入所有力量……！困住你！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"이건?","JPN":"これは？","ENG":"This is?","TWN":"這是？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"바즈라들이... 타기리온을 둘러싸고 있어?","JPN":"ヴァジュラが……タギリオンを囲んでる？","ENG":"The Vajras... they're surrounding Thagirion?","TWN":"金剛杵……包圍塔基里翁了？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"자율수행무기 바즈라.","JPN":"自律遂行武器ヴァジュラ。","ENG":"Autonomous execution weapons, Vajra.","TWN":"自律執行武器金剛杵。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"단독으론 무기일 뿐이지만 다수가 모이면, 위상좌표 변환기 역할도 수행할 수 있죠.","JPN":"単独ではただの武器ですが、複数集まれば位相座標変換器としても機能します。","ENG":"Individually they're just weapons, but when gathered in numbers, they can also function as phase coordinates converters.","TWN":"雖然單個狀態只是武器，但一旦聚集，就能充當位置座標轉換器。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"...위상좌표 변환이라.","JPN":"……位相座標変換。","ENG":"...Phase coordinates converters.","TWN":"……位置座標啊。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"나를 낙원에서 추방이라도 할 셈인가요?","JPN":"私をここから追放でもするつもりですか？","ENG":"Are you planning to banish me from here?","TWN":"你們打算把我驅逐出這裡嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아뇨. 타깃은 당신이 아녜요.","JPN":"いいえ。あなたではありません。","ENG":"No. Not you.","TWN":"不，不是你。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우리 최후의 수단을 여기로 가져올 거거든요!","JPN":"私たちの最後の切り札を、ここに持ってくるつもりです！","ENG":"We're bringing our final measure here instead!","TWN":"是要帶來我們的最後手段。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"최후의 수단?","JPN":"最後の切り札？","ENG":"Your final measure?","TWN":"最後手段？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저건... 대우물이잖아?","JPN":"あれは……大イド？","ENG":"That's... the Great Well, isn't it?","TWN":"那是……大漩井？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"대우물은 서로 다른 두 시공간을 억지로 이어붙이기 위해 막대한 에너지를 응축시켜 놓은 <color=#ffd34c>초고밀도 위상 지점</color>이죠.","JPN":"大イドは異なる2つの時空間を無理やり繋ぐために、莫大なエネルギーを凝縮させた<color=#ffd34c>超高密度位相地点</color>です。","ENG":"The Great Well is an <color=#ffd34c>ultra-high-density phase point</color> where massive energy is condensed to forcibly connect two different spacetime regions.","TWN":"大漩井是為了強行連接兩個不同時空，壓縮龐大能量形成的<color=#ffd34c>超高密度相位點</color>。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지금 이 우물의 출구를 강제로 부수면, 역류하는 에너지가 팽창하던 시공간이 질량을 견디지 못하고 한 점으로 수렴하게 될 겁니다.","JPN":"今このイドの出口を強制的に壊せば、逆流するエネルギーが膨張した時空間の質量に耐えられず、1点に収束するでしょう。","ENG":"If we forcibly destroy the exit of this well now, the energy flowing backward will cause the expanding spacetime to collapse into a single point under its own mass.","TWN":"如果你現在強行破壞大漩井的出口，逆流的能量會讓膨脹的時空承受不住質量，最終化為一個點。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"...블랙홀에 준하는 특이점이 발생하겠군요.","JPN":"……ブラックホール並の特異点が発生しますね。","ENG":"...That would create a singularity comparable to a black hole.","TWN":"……會產生等同黑洞的一個奇特的點呢。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만, 그 방법을 쓰는 순간 당신들이 현실로 돌아갈 방법도 사라질 텐데요?","JPN":"ですがその手を使うと同時に、あなたたちが現実に戻る方法も消えるはずです。","ENG":"But the moment you use that method, you'll lose any way of returning to reality as well.","TWN":"但這樣一來，你們也回不了現實了吧？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"난 이 작전에 찬성이야.","JPN":"私たちのことは心配してくれなくて結構だよ。","ENG":"You don't need to worry about us.","TWN":"不用擔心我們。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어차피 이곳에서 널 꺾지 못하면, 현실로 돌아가도 아무런 의미가 없거든.","JPN":"どうせここであなたを倒せなければ、現実に戻っても意味がないからね。","ENG":"If we can't defeat you here anyway, then there's no point in returning to reality.","TWN":"反正如果我們沒能在這裡打你，回去也沒有意義。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"여러분! 말씀드린대로 가장 강력한 한 방을 부탁 드려요!","JPN":"皆さん！　最高の一撃をお願いします！","ENG":"Everyone! Please give it your strongest strike!","TWN":"各位！請使出最強的一擊！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"…준비는 마쳤사옵니다!","JPN":"……はい！","ENG":"...Okay!","TWN":"……是！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_ENERGY_CHARGE"},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"맡겨주세요! 전부 쏟아 넣을 테니까!","JPN":"任せてください！　全力を注ぎ込みますから！","ENG":"Leave it to me! I'll pour everything into it!","TWN":"交給我們！全部灌入！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"저 역시, 최대 출력으로 부응해드리죠.","JPN":"アヴェスター・ドライブ、最高出力。","ENG":"Avesta Drive. Maximum output.","TWN":"阿貝斯塔引擎，最大輸出。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"울브즈베인...!","JPN":"ウルブズベイン……！","ENG":"Wolvesbane...!","TWN":"狼之災禍……！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"큭...?!","JPN":"くっ……！？","ENG":"Krgh...?!","TWN":"咳……？！"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"검이... 훨씬 무거워졌어.","JPN":"剣が……前よりずっと重い。","ENG":"The blade... it's gotten much heavier.","TWN":"劍……變得更重了。"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신은 이제 곧, 늑대가 아닌 평범한 인간이 되겠죠.","JPN":"あなたはもうすぐオオカミではない、普通の人間になるでしょう。","ENG":"Before long, you will become an ordinary human and no longer a Wolf.","TWN":"你很快就不再是狼，而只是普通的人類。"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아직은 안돼...","JPN":"まだダメ……","ENG":"Not yet...","TWN":"現在還不行……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"적어도, 이번 한 번 만은 어떻게든...!","JPN":"せめて、この1回だけでも、なんとか……！","ENG":"At least this one time, somehow...!","TWN":"至少這次一定要撐住……！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하아아앗!!!!","JPN":"はあああっ！！！","ENG":"Haaaaah!!!!","TWN":"喝啊啊啊啊！！！！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_ENERGY_ATTACK_BIG_18"},{"id":"L6_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"인형이... 공격을 멈췄어?","JPN":"人形が……攻撃を止めた？","ENG":"The dolls... they stopped attacking?","TWN":"人偶……停止攻擊了？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"...지휘관. 보여?","JPN":"……指揮官。見えるか？","ENG":"...Commander. Do you see that?","TWN":"……指揮官，看到了嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그래. 타기리온의 인형들이 더 이상 움직이지 않는 것 같군.","JPN":"ああ。タギリオンの人形たちが動きを止めたようだな。","ENG":"Yes. It seems Thagirion's dolls are no longer moving.","TWN":"是啊，塔基里翁的人偶似乎全停下來了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"하아... 드디어 끝난 건가요?","JPN":"はあ……やっと終わったんですか？","ENG":"*Sigh...* Is it finally over?","TWN":"哈啊……終於結束了嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"방심하지 마. 아직 움직이는 게 있을지도 모르니 주의해서 부수자고.","JPN":"油断するな。まだ動いてるやつが残ってるかもしれねえ。慎重に壊そう。","ENG":"Don't let your guard down just yet. There might still be some moving. Stay alert and destroy them carefully.","TWN":"別大意。說不定還有殘存的，小心點一一破壞吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"이거... 늑대가 해낸 건가?","JPN":"これって……オオカミがやったってことだよね？","ENG":"The... Wolf did it, right?","TWN":"這是……狼做到的吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"아마도.","JPN":"さあな。","ENG":"Who knows.","TWN":"有可能。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"끝난 거라고 보나?","JPN":"終わったと見るか？","ENG":"Do you think it's over?","TWN":"看來結束了嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"타기리온의 인형들이 멈췄다면 그럴 만한 이유가 있겠죠.","JPN":"タギリオンの人形が止まったのは、何か理由があるからでしょう。","ENG":"If Thagirion's dolls have stopped, there must be a reason for it.","TWN":"一定有什麼原因讓塔基里翁的人偶停止。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 모든 게 끝났다고 하기엔, 저희가 목표로 하던 황금나무의 신성은 여전히 빛나고 있군요.","JPN":"ただ、すべてが終わったとするには、私たちの目標である黄金の木の神聖の光はまだ消えていません。","ENG":"But if we're to say everything is over, the Divinity of the Golden Tree we were aiming for is still shining.","TWN":"但說一切都結束了還太早，我們的目標黃金樹的神性依然在發光。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"저 황금나무가... 애초에 타기리온의 왕좌가 아니었을 가능성도 있겠군.","JPN":"そもそもあの黄金の木が……タギリオンの玉座ではなかったのかもしれないな。","ENG":"That Golden Tree... it's possible it was never Thagirion's throne to begin with.","TWN":"……也有可能，那棵樹從一開始就不是塔基里翁的王座。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저토록 빛나는 황금나무의 뒤편에, 숨겨진 진짜 왕좌가 있다 라.......","JPN":"ですがその理由を聞かれたら……そうですね。","ENG":"But if you ask me why, well.","TWN":"至於理由啊，這個嘛。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그들이 직접 황금나무로 가서 그 진상을 파헤쳐보는 수밖에 없겠네요.","JPN":"私たちが直接黄金の木に行って、確かめるしかなさそうです。","ENG":"The only way is for us to go to the Golden Tree and uncover its purpose ourselves.","TWN":"只能我們直接去黃金樹，親自查清楚那個目的了。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"...그래.","JPN":"……ああ。","ENG":"...Right.","TWN":"……嗯。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이번 클리포트 게임은 하나부터 열까지 이전과 달라. 함부로 넘겨짚는 순간 돌이킬 수 없는 결과로 이어지겠지.","JPN":"今回のクリフォートゲームは何もかもが以前と違う。迂闊に行動したら取り返しのつかない結果に繋がるだろう。","ENG":"This Qliphoth Game is different from before in every way. If we make careless assumptions, it could lead to irreversible consequences.","TWN":"這次逆卡巴拉遊戲從頭到尾都不同。一旦胡亂揣測，後果將不堪設想。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"헉... 헉... 크윽.","JPN":"はあ……はあ……げほっ。","ENG":"*Huff... Huff...* *Cough*","TWN":"哈……哈……咳。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배! 죽으면 안돼요!","JPN":"ミナ先輩！　死んじゃダメです！","ENG":"Mina! You can't die!","TWN":"米娜前輩！你不能死！"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"오버하지 마, 노엘. 힘이 안 들어가서 억지 좀 부린 것 뿐이니까.","JPN":"大袈裟なこと言わないで、ノエル。力が入らなくてちょっと無茶しただけだから。","ENG":"Don't overreact, Noelle. I just forced myself a bit since I couldn't put strength into it.","TWN":"別這麼誇張，洛艾兒。我只是沒力氣硬撐而已。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그보다, 너야말로... 상태가 안 좋은 거 같은데.","JPN":"それより、ノエルこそ……具合が悪そうだけど。","ENG":"More importantly, you... don't look well yourself.","TWN":"倒是你……狀況更差吧。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헤헤... 전 괜찮아요.","JPN":"へへ……私は大丈夫です。","ENG":"Hehe... I'm fine.","TWN":"嘿嘿……我沒事。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"괜찮을 리 없겠죠. 세피라의 파편일 뿐인 몸으로 대균열을 막아낸 것도 모자라, 마왕의 움직임을 억지로 묶기까지 했으니까요.","JPN":"大丈夫なはずがありません。セフィラの破片にすぎない体で大亀裂を止めた上に、魔王の動きを無理やり封じたんですから。","ENG":"Of course you're not. It wasn't enough that you stopped the Grand Dimension Crevice with a body that's only a Fragment of Sephira, you even forcibly restrained the Demon Lord's movements.","TWN":"怎麼可能沒事。你不僅用塞菲拉碎片的身體阻止大峽谷，還強行束縛魔王的行動。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"뭐에요. 제 한계를 멋대로 평가하지...!","JPN":"何ですか。私の限界を勝手に決めないでくだ……！","ENG":"What are you saying? Don't go deciding my limits on your own...!","TWN":"什麼啊，別擅自替我評估極限……！"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꺄아악!","JPN":"きゃあっ！","ENG":"Kyaaaah!","TWN":"呀啊啊！"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"스스로의 한계를 알지 못하는 것만큼 위험한 것도 없습니다.","JPN":"自らの限界が分からないほど危ないことはありません。","ENG":"There's nothing more dangerous than not knowing your own limits.","TWN":"不知道自己極限才是最危險的。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"솔직히 전, 게임이 이기기 위해서라면 당신이 희생되어도 별로 상관없으니 계획에 따르긴 했습니다만...","JPN":"正直僕は、ゲームに勝つためならあなたが犠牲になっても構わないので計画に従いましたが……","ENG":"Honestly, I followed the plan because winning the game matters more to me than whether you were sacrificed or not...","TWN":"老實說，只要能贏，就算你犧牲我也無所謂，所以我才會照計畫進行……"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"...지금처럼 힘도 못 쓰는 상태에선 괜히 나서지 말아요. 오히려 일만 그르칠 테니까.","JPN":"……こんなまともに力も使えない状態で無茶しないでください。かえって足手まといになります。","ENG":"...But in a state where you can't even use your strength like this, don't step forward unnecessarily. You'll only make things worse.","TWN":"……但你現在這種無法使力的狀態就別逞強了，反而會拖累大家。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"에이, 방금 전까지 함께 열심히 싸웠는데 다투지 마세요.","JPN":"まあまあ、さっきまで力を合わせて戦ってたのにケンカしないでくださいよ。","ENG":"Hey, you just fought hard together. Don't start arguing now.","TWN":"欸，剛剛還一起拼命戰鬥，不要吵架啦。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이제 전부 해결됐으니 무사히 돌아가는 일만 남았...","JPN":"これで全部解決しましたし、あとは無事帰るだけ……","ENG":"Now everything's been resolved, so all that's left is to return safely–","TWN":"事情都解決了，只剩下回去……"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"중사. 우리, 방금 전에 돌아가는 길을 스스로 무너뜨렸어.","JPN":"軍曹。私たちさっき戻る手段を自分たちの手で壊したじゃない。","ENG":"Sergeant. We already destroyed our own way back earlier.","TWN":"中士，我們剛剛毀了回去的路了。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아차... 그랬었지.","JPN":"あちゃ……そうでした。","ENG":"Oh right... We did.","TWN":"啊……對喔。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"게다가, 프라이머 양은 아직 거울에서 나오지 못한 것 같군요.","JPN":"それに、プライマーさんはまだ鏡から出てきていません。","ENG":"Besides, it seems Nicole Primer still hasn't come out of the mirror.","TWN":"而且，布萊伊莫小姐好像還沒從鏡子裡出來。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"강제로 꺼낼 방법 같은 건 없습니까?","JPN":"強制的に引きずり出す方法はありませんか。","ENG":"Is there any way to force her out?","TWN":"沒有強制拉她出來的方法嗎？"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"걱정 마세요. 그거라면 선배가 하실 수 있을 거에요.","JPN":"心配いりません。それなら先輩ができるはずです。","ENG":"Don't worry. If it's that, Senior can do it.","TWN":"別擔心，這個前輩可以做到。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"검으로 샥- 하고 공간을 멋지게 열어서- 내 손 잡아! 노엘! 하셨던 것처럼요.","JPN":"剣でちゃちゃっと、空間を格好よく切り開いて……手を取って、ノエル！　ってやったみたいに。","ENG":"Like when you went \\"shhk–\\" and opened space with your sword and said, \\"Grab my hand, Noelle!\\"","TWN":"像之前那樣用劍帥氣地—切開空間—說著抓住我的手！洛艾兒！那樣！"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"노엘, 미안하지만 지금의 난...","JPN":"ノエル、悪いけど今の私は……","ENG":"Noelle, I'm sorry, but right now I...","TWN":"洛艾兒，抱歉，但現在我……"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"방법이 없는 건 아니겠지만, 일단은 내버려두도록 하죠.","JPN":"方法はなくはないですが、とりあえず保留にしましょう。","ENG":"It's not that there's no way, but for now, let's leave her be.","TWN":"不是沒有方法，但先別動她吧。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네? 왜요?","JPN":"え？　どうしてですか？","ENG":"Huh? Why?","TWN":"欸？為什麼？"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"파노라마의 시련을 방해하는 건 당사자의 정신에 부담을 줄 수 있거든요.","JPN":"パノラマの試練を邪魔すると、当事者の精神に負担を与えかねません。","ENG":"Interfering with the Trial of Panorama can put a mental strain on the one undergoing it.","TWN":"干涉全景的試煉，可能會對當事人的精神造成負擔。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"...비켜주시죠. 전 어서 모모를 구하러 가야해요.","JPN":"……退いてください。私は早くモモを助けにいかないといけないんです。","ENG":"...Please step aside. I need to go save Momo right away.","TWN":"……讓開。我得去救莫莫。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_MIRROR","text":{"KOREA":"...미안하지만, 그럴 순 없어요.","JPN":"……すみませんが、そうはいきません。","ENG":"...I'm sorry, but I can't allow that.","TWN":"……抱歉，不行。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_MIRROR","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_MIRROR","text":{"KOREA":"당신의 소녀는 마왕과 이어진 영혼, 그 아일 구하겠다는 건 타기리온을 구한다는 말과 다름없죠.","JPN":"あなたの少女は魔王と繋がっている魂。あの子を助けることは、タギリオンを助けることと同じです。","ENG":"The girl you speak of is a soul connected to the Demon Lord. Trying to save that child is no different from trying to save Thagirion.","TWN":"那孩子的靈魂與魔王相連。救她，就等於救塔基里翁。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"모모는 모모에요. 타기리온 같은 진짜 마왕과는 아무런 상관도 없다고요!","JPN":"モモはモモです。本物の魔王タギリオンなんかとは何の関係もないんです！","ENG":"Momo is Momo. She has nothing to do with a true Demon Lord like Thagirion!","TWN":"莫莫就是莫莫！她跟塔基里翁那種真正的魔王一點關係都沒有！"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_MIRROR","text":{"KOREA":"부정하고 있지만, 지금까지의 일들로 당신도 어렴풋이 이해했을 테죠. 그 아이는 본래 죽었어야 할 운명을 타기리온의 파편으로 부지하고 있던 거란걸.","JPN":"否定しているけど、今までのことであなたもうっすらと気づいているはずです。あの子は本来は死ぬはずだった運命を、タギリオンの破片で繋ぎ止めていただけだということに。","ENG":"You deny it, but after everything that's happened, you must already understand it on some level. That child was sustaining a fate that should have ended in death through a Fragment of Thagirion.","TWN":"雖然你嘴上否認，但看到迄今發生的事，你心裡其實也明白吧。那孩子原本就是應該要死去的命運，只是靠塔基里翁的碎片維持著。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_MIRROR","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_MIRROR","text":{"KOREA":"마왕 타기리온을 멸하고자 한다면... 그 아일 구하겠다는 당신의 뜻은 이뤄질 수 없어요.","JPN":"魔王タギリオンを倒そうとするなら……あの子を救いたいというあなたの願いは叶えられません。","ENG":"If you truly intend to destroy the Demon Lord Thagirion... then your wish to save that child cannot be fulfilled.","TWN":"如果要消滅魔王塔基里翁……你想救她的願望，是不可能實現的。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_MIRROR","face":"UNIT_SERIOUS2"}}}},{"id":"L22_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_MIRROR","text":{"KOREA":"정해진 운명은 바꿀 수 없으니까요.","JPN":"定められた運命は変えられませんから。","ENG":"Because a predetermined fate cannot be changed.","TWN":"無法改變既定的命運。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_MIRROR","text":{"KOREA":"당신은 발버둥치다 실패하고, 후회하겠죠.","JPN":"あなたはもがき、失敗し、後悔するでしょう。","ENG":"You will struggle, fail, and regret it.","TWN":"你會掙扎、失敗再後悔。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_MIRROR","face":"UNIT_SERIOUS2"}}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"모르가나는...!","JPN":"モルガナは……！","ENG":"Morgana...!","TWN":"莫甘娜是……！"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_MIRROR","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"당신이 어떤 결말을 불러올지 알면서도, 자신이 어떤 운명으로 끝날지 알면서도, 마지막까지 그 운명을 부정하지 않고 받아들였어.","JPN":"あなたがどんな結末を呼び寄せるか知ってて、自分の運命の終わりを知ってて、それでも最後までその運命を否定せず受け入れた。","ENG":"Even knowing what ending you would bring about, even knowing what fate awaited you, you still accepted that fate without denying it until the very end.","TWN":"你明明知道會導致什麼樣的結局，也知道自己的命運，卻到最後都沒有否定它，而是選擇接受。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그런 아이를 혼자 남겨둔 채 외면하는 게 당신이 말한 내 운명이라면...!","JPN":"そんな子を一人にして知らないふりをするのが、あなたの言う私の運命なら……！","ENG":"If the fate you speak of is abandoning a child like her all alone and turning away from her...!","TWN":"如果那樣的孩子被獨自拋下，就是你說的命運……！"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"난 그 운명을 부정하고, 내 의지를 따르겠어.","JPN":"私はその運命を否定し、自分の意志に従う。","ENG":"Then I will deny that fate and follow my own will.","TWN":"我會否定那個命運，追隨我自己的意志。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_MIRROR","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"있잖아, 루.","JPN":"あのね、ルー。","ENG":"You know, Lugh.","TWN":"你知道嗎，露。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_G1","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그루터기는 줄곧 예언으로부터 도망치기 위해 노력해왔어.","JPN":"切り株はずっと予言から逃れようと努力してきた。","ENG":"The Stump has been trying to escape the prophecy all along.","TWN":"木墩一直在努力預防預言。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_G1","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"낙원문을 완성시켜서 우리가 낙원으로 이주할 수만 있다면... 종말을 피할 수 있을 거라 믿었어.","JPN":"楽園の門を完成させて、あたしたちが楽園に移住できれば……終焉を避けることができると信じてたの。","ENG":"We believed that we could avoid the end... if we could complete Avalon's Gate and send everyone to the Promised Land.","TWN":"我們一直相信…如果我們能完成樂園門的研究，遷移到樂園…就能夠逃避末日。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_G1","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그런데 말이야.","JPN":"でもね。","ENG":"But...","TWN":"不過呢。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_G1","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"운명을 피하는 방법이 소중한 것들을 남기고 도망치는 거라면...","JPN":"運命を変える方法が大切なものを残して逃げることなら……","ENG":"If avoiding fate means that I have to leave behind the things I cherish…","TWN":"如果躲避命運的方法是拋下珍貴的東西落荒而逃…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_G1","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"난 차라리, 내 운명을 받아들일래.","JPN":"あたしはむしろ、あたしの運命を受け入れる。","ENG":"Then I'd rather accept my fate instead.","TWN":"我寧願接受我的命運。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_G1","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_MIRROR","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_MIRROR","text":{"KOREA":"내 이름은 모드레드. 타기리온에게 맞섰으나, 끝내 소중한 사람을 구하지 못한 대적자.","JPN":"私の名はモードレッド。タギリオンに立ち向かい、大切な人を救えなかった敵対者。","ENG":"My name is Mordred. The Antagonist who stood against Thagirion, yet failed to save someone precious in the end.","TWN":"我的名字是莫德雷德。是曾對抗塔基里翁，卻沒能拯救重要之人的敵對者。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_MIRROR","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_MIRROR","text":{"KOREA":"지금부터 당신이 저라는 운명을 뛰어넘을 수 있을지...","JPN":"今からあなたが私という運命を乗り越えられるか……","ENG":"From here on... let's see whether you can overcome the fate of becoming me.","TWN":"接下來就來測試你……"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_MIRROR","text":{"KOREA":"...그 의지를 시험해보죠.","JPN":"……あなたの意志を試しましょう。","ENG":"...I will test that resolve.","TWN":"……能否超越我這個命運的意志。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};